using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerToolType]
public static class ApiTools
{
    [McpServerTool, Description("Fetches a post by ID from the external API.")]
    public static async Task<string> GetPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to retrieve.")] int id)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync($"/posts/{id}");
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;

        return $"Title: {root.GetProperty("title").GetString()}\n\n" +
               $"{root.GetProperty("body").GetString()}";
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt to summarize the given text.")]
    public static IList<McpServerPromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Desired style: brief, detailed, or bullet-points.")] string style = "brief")
    {
        return
        [
            new McpServerPromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Summarize the following text in a {style} style:\n\n{text}"
                }
            }
        ];
    }
}

