using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Generates a prompt to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Desired style: brief, detailed, or bullet-points.")] string style = "brief")
    {
        return
        [
            new()
            {
                Role = Role.User,
                Content = new TextContentBlock
                {
                    Text = $"Summarize the following text in a {style} style:\n\n{text}"
                }
            }
        ];
    }
}

